node -e "
const fs = require('fs');
const r = JSON.parse(fs.readFileSync('/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/intermediate/scan-result.json', 'utf8'));
console.log('=== SCAN RESULT ===');
console.log('Name:', r.name);
console.log('Description:', r.description);
console.log('Languages:', r.languages.join(', '));
console.log('Frameworks:', r.frameworks.join(', '));
console.log('Total files:', r.totalFiles);
console.log('Filtered by ignore:', r.filteredByIgnore);
console.log('Estimated complexity:', r.estimatedComplexity);
console.log('');
console.log('=== BY CATEGORY ===');
const scan = JSON.parse(fs.readFileSync('/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/tmp/ua-scan-files.json', 'utf8'));
Object.entries(scan.stats.byCategory).forEach(([k,v]) => console.log('  ' + k + ': ' + v));
console.log('');
console.log('=== BY LANGUAGE ===');
Object.entries(scan.stats.byLanguage).forEach(([k,v]) => console.log('  ' + k + ': ' + v));
console.log('');
console.log('=== DIRECTORY STRUCTURE (top-level dirs) ===');
const dirs = [...new Set(r.files.map(f => f.path.split('/')[0]).filter(d => d && d !== '.'))];
dirs.sort().forEach(d => {
  const cnt = r.files.filter(f => f.path.startsWith(d + '/')).length;
  console.log('  ' + d + '/ (' + cnt + ' files)');
});
console.log('');
console.log('=== IMPORT MAP SAMPLE (first 5 entries with imports) ===');
let count = 0;
for (const [k, v] of Object.entries(r.importMap)) {
  if (v && v.length > 0) {
    console.log('  ' + k + ' -> ' + v.join(', '));
    if (++count >= 5) break;
  }
}
"
